div.font:
read_chan_handler (DMA-ISR, CPU bound)
dma_channel_acknowledge_irq1(read_chan);
// Go through all bitplanes in sequence
if (++bitplane < bcm_sequence_length) {

font.font:
// Set shift to suit next bitplane
shamt = BCM_SEQUENCE[bitplane];
hub75_bitplane_setup_set_shift(..., shamt);
// Set write address to next slice
plane_dst = frame_buffer + (bitplane * (PIXELS>>1));
dma_channel_set_write_addr(write_chan, plane_dst);
// Set read address to start of rgb_buffer
dma_channel_set_read_addr(read_chan, rgb_buffer);
dma_start_channel_mask(read_chan | write_chan);
} else {
// Rebuild of frame_buffer complete - swap to accommodate for next update
frame_buffer = (frame_buffer == fb1) ? fb2 : fb1;
swap_frame_buffer_pending = true;
}
